import { SessionScore } from './score';

/** Source type identifying where a chat session originated. */
export type Source =
  | 'vscode-chat'
  | 'claude-cli'
  | 'codex-cli'
  | 'gemini-cli'
  | 'terminal'
  | 'import';

/** A single message within a chat session. */
export interface ChatMessage {
  id: string;
  sessionId: string;
  role: 'user' | 'assistant' | 'system';
  content: string;
  timestamp: Date;
  tokenCount: number;
  estimatedCostUSD: number;
  model?: string;
  source: Source;
  truncated?: boolean;
}

/** A complete chat session containing messages and metadata. */
export interface ChatSession {
  id: string;
  source: Source;
  startedAt: Date;
  endedAt?: Date;
  model?: string;
  messages: ChatMessage[];
  totalInputTokens: number;
  totalOutputTokens: number;
  totalCostUSD: number;
  status: 'active' | 'complete' | 'interrupted';
  score?: SessionScore;
}

import { Recommendation } from './recommendation';

/** Competency level classification. */
export type KnowledgeLevel = 'novice' | 'beginner' | 'intermediate' | 'proficient' | 'expert';

/** Score for a specific technology detected in chat sessions. */
export interface TechScore {
  technology: string;
  mentions: number;
  score: number;
  level: KnowledgeLevel;
  strengths: string[];
  gaps: string[];
}

/** Overall knowledge depth assessment. */
export interface KnowledgeScore {
  conceptualDepth: number;
  problemSolving: number;
  independenceIndex: number;
  domainKnowledge: number;
  overall: number;
  level: KnowledgeLevel;
  byTechnology: TechScore[];
}

/** Prompt quality metrics for a session. */
export interface PromptQuality {
  clarity: number;
  specificity: number;
  contextEfficiency: number;
  followUpQuality: number;
  overallScore: number;
  avgTurnsPerTask: number;
  retryRate: number;
  overContextRate: number;
}

/** Token usage efficiency metrics. */
export interface TokenEfficiency {
  totalTokens: number;
  wastedTokens: number;
  efficiencyPercent: number;
  estimatedCostUSD: number;
}

/** Complete session scoring result. */
export interface SessionScore {
  sessionId: string;
  computedAt: Date;
  knowledge: KnowledgeScore;
  promptQuality: PromptQuality;
  tokenEfficiency: TokenEfficiency;
  byTechnology: TechScore[];
  recommendations: Recommendation[];
}

/** An actionable recommendation for the developer. */
export interface Recommendation {
  id: string;
  rank: number;
  title: string;
  description: string;
  category: 'prompt-habit' | 'learning' | 'efficiency' | 'cost';
  effort: 'low' | 'medium' | 'high';
  tokenSavingsPerMonth?: number;
  costSavingsPerMonth?: number;
  action?: {
    type: 'open-url' | 'send-prompt' | 'open-setting';
    value: string;
  };
}

